@Composable
fun LocalVideoLibrary(
    localVideos: List<LocalVideo>,
    themeColors: ai.wallpaper.aurora.ui.theme.ThemeColors?,
    isLoading: Boolean,
    onLoadMore: () -> Unit,
    onVideoClick: (LocalVideo) -> Unit
) {
    val listState = rememberLazyListState()
    var isVisible by remember { mutableStateOf(true) }
    val offsetY by animateDpAsState(
        targetValue = if (isVisible) 0.dp else 200.dp,
        animationSpec = tween(durationMillis = 300)
    )

    // 自动隐藏倒计时
    LaunchedEffect(isVisible) {
        if (isVisible) {
            delay(10000) // 10秒后自动隐藏
            isVisible = false
        }
    }

    Box(
        modifier = Modifier
            .fillMaxWidth()
            .offset(y = offsetY)
    ) {
        // 横向滑动视频列表
        LazyRow(
            state = listState,
            contentPadding = PaddingValues(horizontal = 16.dp, vertical = 8.dp),
            horizontalArrangement = Arrangement.spacedBy(12.dp),
            modifier = Modifier
                .fillMaxWidth()
                .background(themeColors?.surface ?: MaterialTheme.colorScheme.surface)
        ) {
            // 提示卡片 - 最左边
            item {
                Box(
                    modifier = Modifier
                        .height(160.dp)
                        .padding(horizontal = 8.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Text(
                        text = stringResource(R.string.tap_video_to_set_wallpaper),
                        style = MaterialTheme.typography.bodySmall,
                        color = themeColors?.onSurface ?: MaterialTheme.colorScheme.onSurface,
                        textAlign = androidx.compose.ui.text.style.TextAlign.Center,
                        fontSize = 11.sp
                    )
                }
            }

            items(localVideos) { video ->
                LocalVideoCard(
                    video = video,
                    themeColors = themeColors,
                    onClick = { onVideoClick(video) }
                )
            }

            // 加载更多指示器
            if (localVideos.isNotEmpty()) {
                item {
                    Box(
                        modifier = Modifier
                            .height(160.dp)
                            .clickable { if (!isLoading) onLoadMore() }
                            .padding(horizontal = 8.dp),
                        contentAlignment = Alignment.Center
                    ) {
                        if (isLoading) {
                            CircularProgressIndicator(
                                color = themeColors?.primary ?: MaterialTheme.colorScheme.primary,
                                modifier = Modifier.size(24.dp)
                            )
                        } else {
                            Text(
                                text = stringResource(R.string.swipe_right_to_load_more),
                                style = MaterialTheme.typography.bodySmall,
                                color = themeColors?.onSurface ?: MaterialTheme.colorScheme.onSurface,
                                textAlign = androidx.compose.ui.text.style.TextAlign.Center,
                                fontSize = 11.sp
                            )
                        }
                    }
                }
            }
        }

        // 拖拽按钮 - 右上角半圆形
        Box(
            modifier = Modifier
                .align(Alignment.TopEnd)
                .padding(end = 16.dp)
                .size(40.dp, 20.dp)
                .clip(RoundedCornerShape(bottomStart = 20.dp, bottomEnd = 20.dp))
                .background(themeColors?.buttonBackground ?: MaterialTheme.colorScheme.primary)
                .pointerInput(Unit) {
                    detectVerticalDragGestures(
                        onDragEnd = {
                            // 拖拽结束时切换状态
                            isVisible = !isVisible
                        },
                        onVerticalDrag = { _, dragAmount ->
                            // 向下拖拽（dragAmount > 0）隐藏，向上拖拽（dragAmount < 0）显示
                            if (dragAmount > 10 && isVisible) {
                                isVisible = false
                            } else if (dragAmount < -10 && !isVisible) {
                                isVisible = true
                            }
                        }
                    )
                }
                .clickable { isVisible = !isVisible },
            contentAlignment = Alignment.Center
        ) {
            Icon(
                imageVector = if (isVisible) Icons.Default.KeyboardArrowDown else Icons.Default.KeyboardArrowUp,
                contentDescription = if (isVisible) "Hide" else "Show",
                tint = themeColors?.buttonContent ?: MaterialTheme.colorScheme.onPrimary,
                modifier = Modifier.size(16.dp)
            )
        }
    }

    // 检测滑动到末尾
    LaunchedEffect(listState) {
        snapshotFlow { listState.layoutInfo.visibleItemsInfo.lastOrNull()?.index }
            .collect { lastVisibleIndex ->
                if (lastVisibleIndex != null && lastVisibleIndex >= localVideos.size - 2 && !isLoading) {
                    onLoadMore()
                }
            }
    }
}

