@Composable
fun VideoGridItem(
    video: VideoItem,
    isSelected: Boolean,
    themeColors: ai.wallpaper.aurora.ui.theme.ThemeColors?,
    onVideoTouch: (Int) -> Unit
) {
    val context = LocalContext.current
    var isPlaying by remember { mutableStateOf(false) }
    val exoPlayer = remember {
        ExoPlayer.Builder(context).build().apply {
            video.uri?.let { uri ->
                setMediaItem(MediaItem.fromUri(uri))
                prepare()
                volume = 0f // 静音
                repeatMode = Player.REPEAT_MODE_ONE
            }
        }
    }

    DisposableEffect(Unit) {
        onDispose {
            exoPlayer.release()
        }
    }

    LaunchedEffect(isSelected) {
        if (isSelected) {
            exoPlayer.play()
            isPlaying = true
        } else {
            exoPlayer.pause()
            exoPlayer.seekTo(0)
            isPlaying = false
        }
    }

    Box(
        modifier = Modifier
            .aspectRatio(3f / 4f)
            .clip(RoundedCornerShape(12.dp))
            .border(
                width = 2.dp,
                color = themeColors?.cardBorder ?: MaterialTheme.colorScheme.primary,
                shape = RoundedCornerShape(12.dp)
            )
            .background(MaterialTheme.colorScheme.surface)
            .pointerInput(Unit) {
                detectTapGestures(
                    onPress = {
                        onVideoTouch(video.id)
                        tryAwaitRelease()
                    }
                )
            }
    ) {
        AndroidView(
            factory = { ctx ->
                PlayerView(ctx).apply {
                    player = exoPlayer
                    useController = false
                    layoutParams = android.view.ViewGroup.LayoutParams(
                        android.view.ViewGroup.LayoutParams.MATCH_PARENT,
                        android.view.ViewGroup.LayoutParams.MATCH_PARENT
                    )
                }
            },
            modifier = Modifier.fillMaxSize()
        )
    }
}

private fun loadSavedVideos(context: Context): Uri? {
    return try {
        val file = File(context.filesDir, "video_live_wallpaper_file_path")
        if (file.exists()) {
            val path = file.readText()
            Uri.parse(path)
        } else {
            null
        }
    } catch (e: Exception) {
        null
    }
}

private fun saveVideoUri(context: Context, uri: Uri) {
    // 持久化 URI 权限
    try {
        context.contentResolver.takePersistableUriPermission(
            uri,
            Intent.FLAG_GRANT_READ_URI_PERMISSION
        )
        android.util.Log.d("MainActivity", "Persistable URI permission granted for: $uri")
    } catch (e: Exception) {
        android.util.Log.e("MainActivity", "Failed to take persistable URI permission", e)
    }

    // 保存 URI 路径
    context.openFileOutput("video_live_wallpaper_file_path", Context.MODE_PRIVATE).use {
        it.write(uri.toString().toByteArray())
    }

    // 添加到历史记录
    WallpaperHistoryManager.addHistory(context, uri)

    android.util.Log.d("MainActivity", "Video URI saved: $uri")
}

private fun saveVideoPath(context: Context, path: String) {
    context.openFileOutput("video_live_wallpaper_file_path", Context.MODE_PRIVATE).use {
        it.write(path.toByteArray())
    }
}

@Composable
fun ThemeButton(
    themeName: String,
    themeId: String,
    isSelected: Boolean,
    backgroundColor: Color,
    modifier: Modifier = Modifier,
    onClick: () -> Unit
) {
    Box(
        modifier = modifier
            .height(48.dp)
            .clip(RoundedCornerShape(8.dp))
            .background(backgroundColor.copy(alpha = if (isSelected) 1f else 0.6f))
            .border(
                width = if (isSelected) 2.dp else 0.dp,
                color = Color.White,
                shape = RoundedCornerShape(8.dp)
            )
            .pointerInput(Unit) {
                detectTapGestures(
                    onPress = {
                        onClick()
                        tryAwaitRelease()
                    }
                )
            },
        contentAlignment = Alignment.Center
    ) {
        Text(
            text = themeName,
            style = MaterialTheme.typography.bodyMedium,
            color = Color.White,
            fontWeight = if (isSelected) FontWeight.Bold else FontWeight.Normal
        )
    }
}

@Composable
fun LocalVideoLibrary(
    localVideos: List<LocalVideo>,
    themeColors: ai.wallpaper.aurora.ui.theme.ThemeColors?,
    isLoading: Boolean,
    onLoadMore: () -> Unit,
    onVideoClick: (LocalVideo) -> Unit
) {
    val listState = rememberLazyListState()
    var isVisible by remember { mutableStateOf(true) }
    val offsetY by animateDpAsState(
        targetValue = if (isVisible) 0.dp else 200.dp,
        animationSpec = tween(durationMillis = 300)
    )

    // 自动隐藏倒计时
    LaunchedEffect(isVisible) {
        if (isVisible) {
            delay(10000) // 10秒后自动隐藏
            isVisible = false
        }
    }

    Box(
        modifier = Modifier
            .fillMaxWidth()
            .offset(y = offsetY)
    ) {
        // 横向滑动视频列表
        LazyRow(
            state = listState,
            contentPadding = PaddingValues(horizontal = 16.dp, vertical = 8.dp),
            horizontalArrangement = Arrangement.spacedBy(12.dp),
            modifier = Modifier
                .fillMaxWidth()
                .background(themeColors?.surface ?: MaterialTheme.colorScheme.surface)
        ) {
            // 提示卡片 - 最左边
            item {
                Box(
                    modifier = Modifier
                        .height(160.dp)
                        .padding(horizontal = 8.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Text(
                        text = stringResource(R.string.tap_video_to_set_wallpaper),
                        style = MaterialTheme.typography.bodySmall,
                        color = themeColors?.onSurface ?: MaterialTheme.colorScheme.onSurface,
                        textAlign = androidx.compose.ui.text.style.TextAlign.Center,
                        fontSize = 11.sp
                    )
                }
            }

            items(localVideos) { video ->
                LocalVideoCard(
                    video = video,
                    themeColors = themeColors,
                    onClick = { onVideoClick(video) }
                )
            }

            // 加载更多指示器
            if (localVideos.isNotEmpty()) {
                item {
                    Box(
                        modifier = Modifier
                            .height(160.dp)
                            .clickable { if (!isLoading) onLoadMore() }
                            .padding(horizontal = 8.dp),
                        contentAlignment = Alignment.Center
                    ) {
                        if (isLoading) {
                            CircularProgressIndicator(
                                color = themeColors?.primary ?: MaterialTheme.colorScheme.primary,
                                modifier = Modifier.size(24.dp)
                            )
                        } else {
                            Text(
                                text = stringResource(R.string.swipe_right_to_load_more),
                                style = MaterialTheme.typography.bodySmall,
                                color = themeColors?.onSurface ?: MaterialTheme.colorScheme.onSurface,
                                textAlign = androidx.compose.ui.text.style.TextAlign.Center,
                                fontSize = 11.sp
                            )
                        }
                    }
                }
            }
        }

        // 拖拽按钮 - 右上角半圆形
        Box(
            modifier = Modifier
                .align(Alignment.TopEnd)
                .padding(end = 16.dp)
                .size(40.dp, 20.dp)
                .clip(RoundedCornerShape(bottomStart = 20.dp, bottomEnd = 20.dp))
                .background(themeColors?.buttonBackground ?: MaterialTheme.colorScheme.primary)
                .pointerInput(Unit) {
                    detectVerticalDragGestures(
                        onDragEnd = {
                            // 拖拽结束时切换状态
                            isVisible = !isVisible
                        },
                        onVerticalDrag = { _, dragAmount ->
                            // 向下拖拽（dragAmount > 0）隐藏，向上拖拽（dragAmount < 0）显示
                            if (dragAmount > 10 && isVisible) {
                                isVisible = false
                            } else if (dragAmount < -10 && !isVisible) {
                                isVisible = true
                            }
                        }
                    )
                }
                .clickable { isVisible = !isVisible },
            contentAlignment = Alignment.Center
        ) {
            Icon(
                imageVector = if (isVisible) Icons.Default.KeyboardArrowDown else Icons.Default.KeyboardArrowUp,
                contentDescription = if (isVisible) "Hide" else "Show",
                tint = themeColors?.buttonContent ?: MaterialTheme.colorScheme.onPrimary,
                modifier = Modifier.size(16.dp)
            )
        }
    }

    // 检测滑动到末尾
    LaunchedEffect(listState) {
        snapshotFlow { listState.layoutInfo.visibleItemsInfo.lastOrNull()?.index }
            .collect { lastVisibleIndex ->
                if (lastVisibleIndex != null && lastVisibleIndex >= localVideos.size - 2 && !isLoading) {
                    onLoadMore()
                }
            }
    }
}

@Composable
fun LocalVideoCard(
    video: LocalVideo,
    themeColors: ai.wallpaper.aurora.ui.theme.ThemeColors?,
    onClick: () -> Unit
) {
    val context = LocalContext.current
    val exoPlayer = remember {
        ExoPlayer.Builder(context).build().apply {
            setMediaItem(MediaItem.fromUri(video.uri))
            prepare()
            volume = 0f
            repeatMode = Player.REPEAT_MODE_ONE
        }
    }

    DisposableEffect(Unit) {
        onDispose {
            exoPlayer.release()
        }
    }

    Box(
        modifier = Modifier
            .width(120.dp)
            .height(160.dp)
            .clip(RoundedCornerShape(8.dp))
            .border(
                width = 1.dp,
                color = themeColors?.cardBorder ?: MaterialTheme.colorScheme.primary,
                shape = RoundedCornerShape(8.dp)
            )
            .background(MaterialTheme.colorScheme.surface)
            .clickable { onClick() }
    ) {
        AndroidView(
            factory = { ctx ->
                PlayerView(ctx).apply {
                    player = exoPlayer
                    useController = false
                    layoutParams = android.view.ViewGroup.LayoutParams(
                        android.view.ViewGroup.LayoutParams.MATCH_PARENT,
                        android.view.ViewGroup.LayoutParams.MATCH_PARENT
                    )
                }
            },
            modifier = Modifier.fillMaxSize()
        )

        // 视频名称覆盖层
        Box(
            modifier = Modifier
                .fillMaxWidth()
                .align(Alignment.BottomCenter)
                .background(Color.Black.copy(alpha = 0.6f))
                .padding(4.dp)
        ) {
            Text(
                text = video.displayName,
                style = MaterialTheme.typography.bodySmall,
                color = Color.White,
                maxLines = 1,
                fontSize = 10.sp
            )
        }
    }

    LaunchedEffect(Unit) {
        exoPlayer.play()
    }
}

