    val context = LocalContext.current
    var isPlaying by remember { mutableStateOf(false) }
    var isDeleting by remember { mutableStateOf(false) }

    // 删除动画状态
    val deleteProgress by animateFloatAsState(
        targetValue = if (isDeleting) 1f else 0f,
        animationSpec = tween(durationMillis = 800, easing = LinearEasing),
        finishedListener = {
            if (isDeleting) {
                onVideoLongPress(video.id)
            }
        }
    )

    val exoPlayer = remember {
        ExoPlayer.Builder(context).build().apply {
            video.uri?.let { uri ->
                setMediaItem(MediaItem.fromUri(uri))
                prepare()
                volume = 0f // 静音
                repeatMode = Player.REPEAT_MODE_ONE
            }
        }
    }

    DisposableEffect(Unit) {
        onDispose {
            exoPlayer.release()
        }
    }

    LaunchedEffect(isSelected) {
        if (isSelected) {
            exoPlayer.play()
            isPlaying = true
        } else {
            exoPlayer.pause()
            exoPlayer.seekTo(0)
            isPlaying = false
        }
    }

    Box(
        modifier = Modifier
            .aspectRatio(3f / 4f)
            .graphicsLayer {
                // 顺时针旋转
                rotationZ = deleteProgress * 360f
                // 缩放消失
                scaleX = 1f - deleteProgress
                scaleY = 1f - deleteProgress
                alpha = 1f - deleteProgress
